import{_ as t,o,c as d,ag as a}from"./chunks/framework.HG0H2VLS.js";const g=JSON.parse('{"title":"ControlHub — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/cc/templates/ControlHub/ControlHub.figma-notes.md","filePath":"public/demos/src/cc/templates/ControlHub/ControlHub.figma-notes.md"}'),n={name:"public/demos/src/cc/templates/ControlHub/ControlHub.figma-notes.md"};function r(c,e,i,s,l,p){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="controlhub-—-figma-notes" tabindex="-1">ControlHub — Figma Notes <a class="header-anchor" href="#controlhub-—-figma-notes" aria-label="Permalink to &quot;ControlHub — Figma Notes&quot;">​</a></h1><h2 id="figma-node" tabindex="-1">Figma Node <a class="header-anchor" href="#figma-node" aria-label="Permalink to &quot;Figma Node&quot;">​</a></h2><ul><li><strong>File:</strong> <a href="https://www.figma.com/design/ETKqleZdpertwFEo40YB5n/Affino-CC-Hybrid--Design-System" target="_blank" rel="noreferrer">Affino CC Hybrid – Design System</a> — file key <code>ETKqleZdpertwFEo40YB5n</code></li><li><strong>Component set:</strong> <code>4244:6526</code> — <em>Control Screen</em> (a second Control Centre view; distinct from the dashboard <code>ControlScreen</code>, set <code>4187:21254</code>)</li><li><strong>Tier:</strong> Template</li><li><strong>Brand context:</strong> <code>data-brand=&quot;cc&quot;</code> on <code>&lt;html&gt;</code> activates CC palette tokens</li></ul><h3 id="variant-matrix" tabindex="-1">Variant matrix <a class="header-anchor" href="#variant-matrix" aria-label="Permalink to &quot;Variant matrix&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Node</th><th>Device</th><th>Content frame</th><th>Code mapping</th></tr></thead><tbody><tr><td>4244:6525</td><td>Desktop</td><td><code>4236:6169</code></td><td>3-column card grid; <code>.cc-control__page</code> padding <code>--ai-spacing-6</code>, gap <code>--ai-spacing-7</code>.</td></tr><tr><td>4244:6524</td><td>Mobile</td><td><code>4243:6400</code></td><td>1-column grid; page padding <code>--ai-spacing-4</code>, gap <code>--ai-spacing-6</code>. Reflow via <code>@container cs-page (max-width:767px)</code> + a mobile <code>@media</code> gap override.</td></tr></tbody></table><p>The Menu Open/Collapsed sidebar state is inherited from the reused shell (<code>sidebar-menu.js</code>), not a ControlHub axis.</p><h2 id="composed-components" tabindex="-1">Composed components <a class="header-anchor" href="#composed-components" aria-label="Permalink to &quot;Composed components&quot;">​</a></h2><p>ControlHub owns <strong>only the page-content layout</strong> (filter + sections + grids). Everything else is reused:</p><table tabindex="0"><thead><tr><th>Source</th><th>Role</th></tr></thead><tbody><tr><td><code>src/cc/templates/ControlScreen/ControlScreen.css</code> + its shell markup</td><td><strong>Entire app-shell, reused verbatim</strong> — left rail + Menu panels (<code>SidebarMenu</code> desktop+mobile composites), chrome (<code>HeaderGroup</code> = TopNavigation + Header + IconNavigation), right <code>ActionsMenu</code> rail, <code>AiAssistant</code> panel, <code>AssistantPopover</code> coachmark, favourites toasts. Cloned markup (vanilla-static, no partials) + shared JS (all <code>../</code>-relative paths resolve unchanged from this sibling dir).</td></tr><tr><td><code>src/components/Input/</code></td><td>The <strong>filter</strong> field — <code>.input</code> &gt; <code>.input__wrap</code> with a leading <code>search</code> <code>.input__icon</code>, <code>.input__control</code>, and a <code>.input__clear</code> (auto-shown via <code>:has(:not(:placeholder-shown))</code>). Used verbatim.</td></tr><tr><td><code>src/components/ActionCard/</code> (composes <code>src/components/Button/</code> Tertiary <strong>xs</strong>)</td><td>The directory cards. Two variants per Figma: <strong>Right Chevron</strong> (<code>&lt;a class=&quot;action-card action-card--chevron&quot;&gt;</code>, whole-card nav) and <strong>Button</strong> (<code>&lt;div class=&quot;action-card action-card--button&quot;&gt;</code> with a <code>btn btn--tertiary btn--xs</code> &quot;+ add&quot;). Used verbatim — CC tokens resolve under <code>data-brand=&quot;cc&quot;</code> (e.g. tertiary button bg → <code>#e5e9eb</code>).</td></tr></tbody></table><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><p>Template-owned classes only (every other class belongs to a composed/reused component):</p><table tabindex="0"><thead><tr><th>Class</th><th>Role</th></tr></thead><tbody><tr><td><code>.cc-control__page--directory</code></td><td>Modifier on the reused page scroll container; tightens the mobile inter-block gap to <code>--ai-spacing-6</code>.</td></tr><tr><td><code>.cc-directory__filter</code></td><td>Scoping / backend hook on the filter <code>.input</code> (no extra style — stretches full-width as a flex child).</td></tr><tr><td><code>.cc-directory__section</code></td><td>Section wrapper: flex column, <code>gap --ai-spacing-4</code>.</td></tr><tr><td><code>.cc-directory__section-title</code></td><td>Section heading <code>&lt;h2&gt;</code> — <code>--ai-font-title</code>/<code>--ai-font-bold</code>, <code>--ai-font-fixed-md</code> (18px) → <code>--ai-font-fixed-sm</code> (16px) at <code>@container cs-page (max-width:639px)</code> (single-column view).</td></tr><tr><td><code>.cc-directory__grid</code></td><td>Card grid, <code>gap --ai-spacing-4</code>. Container-query columns on <code>cs-page</code>: <strong>≥1024px → 3 · 640–1023px → 2 · &lt;640px → 1</strong> (per user, 2026-06-12; Figma shows 3 desktop / 1 mobile only).</td></tr><tr><td><code>.cc-directory__grid .action-card--button</code></td><td><code>cursor: pointer</code> — the Button-variant card navigates as a whole (the &quot;+ add&quot; button is a separate action). The Chevron variant is already an <code>&lt;a&gt;</code>.</td></tr></tbody></table><h2 id="card-inventory-figma-content-verbatim-—-same-set-in-both-sections" tabindex="-1">Card inventory (Figma content verbatim — same set in both sections) <a class="header-anchor" href="#card-inventory-figma-content-verbatim-—-same-set-in-both-sections" aria-label="Permalink to &quot;Card inventory (Figma content verbatim — same set in both sections)&quot;">​</a></h2><p>Row-major DOM order 1–10 reproduces Figma&#39;s 3-column layout exactly.</p><table tabindex="0"><thead><tr><th>#</th><th>Title</th><th>Variant</th></tr></thead><tbody><tr><td>1</td><td>Ad Campaign Analysis</td><td>Chevron</td></tr><tr><td>2</td><td>Campaign Dashboards</td><td>Add (Button)</td></tr><tr><td>3</td><td>Lifecycle Analysis</td><td>Chevron</td></tr><tr><td>4</td><td>Conversion Funnels</td><td>Add (Button)</td></tr><tr><td>5</td><td>Converting Articles Report</td><td>Chevron</td></tr><tr><td>6</td><td>Message Analysis</td><td>Chevron</td></tr><tr><td>7</td><td>Message Campaign Analysis</td><td>Chevron</td></tr><tr><td>8</td><td>Mailing List Analysis</td><td>Add (Button)</td></tr><tr><td>9</td><td>Mailing List Removal Log</td><td>Chevron</td></tr><tr><td>10</td><td>Referral Analysis</td><td>Chevron</td></tr></tbody></table><p>Sections: <strong>Analysis</strong>, <strong>Ad Campaigns</strong> (identical card sets).</p><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>Where</th></tr></thead><tbody><tr><td><code>--ai-spacing-6</code></td><td>Page padding (desktop, reused); mobile inter-block gap</td></tr><tr><td><code>--ai-spacing-7</code></td><td>Inter-block gap (desktop, reused)</td></tr><tr><td><code>--ai-spacing-4</code></td><td>Page padding (mobile, reused); section gap; grid gap</td></tr><tr><td><code>--ai-font-title</code> / <code>--ai-font-bold</code></td><td>Section heading</td></tr><tr><td><code>--ai-font-fixed-md</code> / <code>--ai-font-fixed-sm</code></td><td>Section heading size (desktop / mobile)</td></tr><tr><td><code>--ai-leading-md</code></td><td>Section heading line height</td></tr><tr><td><code>--ai-text-primary</code></td><td>Section heading colour</td></tr></tbody></table><p>(Filter Input and ActionCards carry their own component tokens.)</p><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None at template scope.</p><p><strong>Noted (not a gap):</strong> the Figma filter <code>Field</code> (<code>I4236:6853;78:2020</code>) uses <code>px-[--ai-spacing-5]</code> (16px), but the codebase <code>Input</code> component uses <code>--ai-spacing-4</code> (12px). Per user decision (2026-06-12) the Input is used <strong>verbatim</strong> (12px) — treated as a cross-file Input difference, not a deliberate per-instance override. No template CSS added for it.</p><h2 id="js-interactivity" tabindex="-1">JS / Interactivity <a class="header-anchor" href="#js-interactivity" aria-label="Permalink to &quot;JS / Interactivity&quot;">​</a></h2><p>No new JS. The shell&#39;s scripts (sidebar-menu, HeaderGroup, Dropdown, Select, Alert, ThemeToggle, FontSizeSlider, AiAssistant shell, AssistantPopover/toasts module, Lucide) are reused as-is from the cloned footer.</p><p><strong>Visual-only (backend TODOs in markup):</strong></p><ul><li>Filter input — no client-side filtering wired (<code>data-backend-todo=&quot;controlhub-filter&quot;</code>).</li><li>ActionCard cards navigate as a whole (both Chevron and Button variants → a page); the Button variant additionally has a separate &quot;+ add&quot; action. Chevron links are <code>href=&quot;#&quot;</code>, the card-level navigation on Button cards isn&#39;t wired (pointer cursor only), and &quot;add&quot; buttons are inert. When wiring the Button card, use a stretched-link (<code>&lt;a&gt;</code> with <code>::after</code> covering the card) so the whole card navigates while the &quot;+ add&quot; <code>&lt;button&gt;</code> stays a separate click above it.</li></ul><p>See <code>TODO(backend:ControlHub)</code> markers in <code>ControlHub.html</code> and the <code>ControlHub</code> surface in <code>docs/handover-manifest.json</code>.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Distinct from ControlScreen.</strong> Same Figma file, same &quot;Control Screen&quot; name, but a different view (filterable directory vs dashboard). Lives in its own <code>src/cc/templates/ControlHub/</code> and reuses ControlScreen&#39;s shell CSS rather than duplicating it.</li><li><strong>Page paint values matched the shell.</strong> Desktop padding/gap (<code>--ai-spacing-6</code>/<code>--ai-spacing-7</code>) and mobile padding (<code>--ai-spacing-4</code>) already match the reused <code>.cc-control__page</code>; only the mobile gap needed an override.</li><li><strong>Reflow on <code>@container cs-page</code></strong> for the grid + heading (descendants of the page container); the page&#39;s own mobile gap uses <code>@media</code> because an element can&#39;t query its own container.</li><li>Lucide names: Figma <code>Icon/24px/Search</code> → <code>search</code>; <code>Icon/16px/X</code> → <code>x</code>; <code>Icon/24px/Plus</code> → <code>plus</code>; <code>Icon/24px/ChevronRight</code> → <code>chevron-right</code>.</li></ul>',29)])])}const u=t(n,[["render",r]]);export{g as __pageData,u as default};
